db.minutes.aggregate([
  {
    "$search": {
      "text": {
        "query": "صحبت",
        "path": "text.fa_IR"
      }
    }
  },
  {
    "$project": {
      "_id": 1,
      "text.fa_IR": 1,
      "page_updated_by.last_name": 1
    }
  }
])
